items(viewModel.savedScripts, key = { it.id }) { script ->
    val dismissState = rememberSwipeToDismissBoxState()
    if (dismissState.currentValue == SwipeToDismissBoxValue.EndToStart) {
         viewModel.deleteScript(context, script.id)
    }

    SwipeToDismissBox(
        state = dismissState,
        backgroundContent = { 
            Box(Modifier.fillMaxSize().background(Color.Red.copy(alpha = 0.2f)).padding(end = 20.dp), contentAlignment = Alignment.CenterEnd) {
                Icon(Icons.Default.Delete, null, tint = Color.Red)
            }
        },
        enableDismissFromStartToEnd = false
    ) {
        NavigationDrawerItem(
            label = { 
                Column { 
                    Text(script.title, fontWeight = FontWeight.Bold) 
                    Text(script.code.take(40).replace("\n", " ") + "...", style = MaterialTheme.typography.bodySmall, color = Color.Gray) 
                }
            },
            selected = false,
            onClick = { 
                viewModel.manualCode = script.code
                scope.launch { drawerState.close() }
            },
            modifier = Modifier.combinedClickable(
                onClick = { 
                    viewModel.manualCode = script.code
                    scope.launch { drawerState.close() }
                },
                onLongClick = { 
                    scriptToRename = script
                    newTitleName = script.title
                }
            ),
            icon = { Icon(Icons.Default.Description, null, tint = Color(0xFF7C4DFF)) }
        )
    }
}

