193 | fun parseInlineMarkdown(text: String): androidx.compose.ui.text.AnnotatedString {
194 |     return buildAnnotatedString {
195 |         val pattern = "(\\*\\*.*?\\*\\*|`.*?`)".toRegex()
196 |         var lastIndex = 0
197 |         
198 |         pattern.findAll(text).forEach { match ->
199 |             append(text.substring(lastIndex, match.range.first))
200 |             val matchText = match.value
201 |             when {
202 |                 matchText.startsWith("**") && matchText.endsWith("**") -> {
203 |                     withStyle(style = SpanStyle(fontWeight = FontWeight.Bold, color = Color.White)) {
204 |                         append(matchText.removeSurrounding("**"))
205 |                     }
206 |                 }
207 |                 matchText.startsWith("`") && matchText.endsWith("`") -> {
208 |                     withStyle(style = SpanStyle(
209 |                         fontFamily = FontFamily.Monospace, 
210 |                         background = Color.Black.copy(alpha = 0.3f), 
211 |                         color = Color(0xFF80CBC4)
212 |                     )) {
213 |                         append(matchText.removeSurrounding("`"))
214 |                     }
215 |                 }
216 |                 else -> append(matchText)
217 |             }
218 |             lastIndex = match.range.last + 1
219 |         }
220 |         append(text.substring(lastIndex))
221 |     }
222 | }
